description:
Max/Min for enum get different result whether using index
How to repeat:
drop table t;
create table t(a enum('y','b','1','x','0','null') DEFAULT NULL,key(a));
insert into t values('y'),('b');
select min(a) from t;
MySQL [test]> select min(a) from t;
+--------+
| min(a) |
+--------+
| y      |
+--------+
1 row in set (0.000 sec)

drop table t;
create table t(a enum('y','b','1','x','0','null') DEFAULT NULL);
insert into t values('y'),('b');
select min(a) from t;
MySQL [test]> select min(a) from t;
+--------+
| min(a) |
+--------+
| b      |
+--------+
1 row in set (0.000 sec)
